(X^T Z (Z^T Z)^{-1} Z^T X)^{-1}
X^T Z (Z^T Z)^{-1}Z^T y

\begin{align}
\hat{\beta}_{GMM}
&= (X^T Z (Z^T Z)^{-1} Z^T X)^{-1}
X^T Z (Z^T Z)^{-1}Z^T y\\
&= (Z^T X)^{-1} (X^T Z (Z^T Z)^{-1})^{-1}
X^T Z (Z^T Z)^{-1}Z^T y\\
&= (Z^T X)^{-1} (Z^T Z)(X^T Z)^{-1}
X^T Z (Z^T Z)^{-1}Z^T y\\
&= (Z^T X)^{-1}Z^T y
\end{align}
